// service-worker.js (background)
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type === 'SCRAPE_PAGE') {
    // Process scraping request, coordinate with content script
    chrome.tabs.sendMessage(sender.tab.id, {
      type: 'EXTRACT_DATA',
      fields: message.fields
    });
    sendResponse({ status: 'request_sent' });
  }
});

// content-script.js
// Extract product data from an e-commerce page
function extractProducts() {
  const products = document.querySelectorAll('.product-card');
  return products.map(product => ({
    title: product.querySelector('.title').textContent,
    price: product.querySelector('.price').textContent,
    sku: product.dataset.sku
  }));
}

// Listen for extraction requests from background
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message.type === 'EXTRACT_DATA') {
    const data = extractProducts();
    sendResponse({ products: data });
  }
});

// Send data to background when page loads
chrome.runtime.sendMessage({
  type: 'SCRAPE_PAGE',
  data: extractProducts()
});

// popup.js
document.getElementById('scrapeBtn').addEventListener('click', async () => {
  const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });

  chrome.tabs.sendMessage(tab.id, {
    type: 'SCRAPE_PAGE',
    fields: ['title', 'price', 'sku']
  }, (response) => {
    if (response && response.products) {
      displayResults(response.products);
    }
  });
});

function displayResults(products) {
  const container = document.getElementById('results');
  container.innerHTML = products.map(p => 
    `<div class="product">${p.title} - ${p.price}</div>`
  ).join('');
}
